    "help": {
      "udl_modal_title": "Przewodnik po Uniwersalnym Projektowaniu dla Uczenia się (UDL)",
      "udl_modal_desc": "Ten kompleksowy przewodnik pomoże Panu/Pani zrozumieć zasady UDL i zastosować je w nauczaniu. Proszę go używać do tworzenia bardziej dostępnych i angażujących doświadczeń edukacyjnych dla wszystkich uczniów.",
      "header_actions_title": "Akcje nagłówka",
      "header_actions_desc": "Elementy szybkiego dostępu do ustawień języka, opcji dostępności i przełączania trybu użytkownika. Tutaj można dostosować swoje doświadczenie z AlloFlow.",
      "header_utils_title": "Elementy sterujące",
      "header_utils_desc": "Niezbędne narzędzia, w tym zarządzanie projektem, zasoby pomocy i przełącznik trybu użytkownika. Przełączaj między trybem Nauczyciela i Ucznia lub uzyskaj dostęp do zapisanej pracy.",
      "header_tools_title": "Szybkie narzędzia",
      "header_tools_desc": "Narzędzia mocy do tworzenia treści i wsparcia AI. Uzyskaj dostęp do warsztatu pisarskiego, asystenta czatu i innych funkcji produktywności.",
      "lesson_plan_title": "Planowanie lekcji",
      "lesson_plan_desc": "Skonfiguruj parametry lekcji, w tym czas trwania, poziom klasy, obszary treści i cele uczenia. Te ustawienia pomagają dostosować treść generowaną przez AI do twoich konkretnych potrzeb.",
      "tool_udl_title": "Przełącznik przewodnika UDL",
      "tool_udl_desc": "Przełącz pasek boczny Universal Design for Learning, aby zobaczyć wytyczne i punkty kontrolne podczas pracy. Użyj tego, aby zapewnić, że twoje materiały są dostępne i angażujące.",
      "tool_chat_title": "Asystent czatu AI",
      "tool_chat_desc": "Otwórz asystenta czatu AI dla interaktywnej pomocy z twoją treścią. Zadawaj pytania, uzyskuj sugestie lub proś o modyfikacje swoich materiałów.",
      "tool_writing_title": "Warsztaty pisarskie",
      "tool_writing_desc": "Uruchom środowisko wspólnego pisania, w którym uczniowie mogą szkicować, redagować i otrzymywać informacje zwrotne AI o swoim pisaniu.",
      "sidebar_analysis_title": "Analiza tekstu",
      "sidebar_analysis_desc": "Analiza tekstu źródłowego oparta na AI, w tym ocena poziomu czytania, identyfikacja kluczowego słownictwa i podział struktury treści.",
      "sidebar_glossary_title": "Inteligentny słowniczek",
      "sidebar_glossary_desc": "Automatycznie wyodrębnione terminy słownictwa z definicjami, tłumaczeniami i wizualnymi ikonami. Edytuj terminy, dodawaj tłumaczenia i twórz fiszki.",
      "sidebar_simplified_title": "Uproszczone wersje",
      "sidebar_simplified_desc": "Uzyskaj dostęp do zróżnicowanych wersji tekstu na różnych poziomach czytania. Generuj uproszczone treści, dwujęzyczne wersje obok siebie oraz zmodyfikowane teksty.",
      "sidebar_outline_title": "Wizualne organizatory",
      "sidebar_outline_desc": "Twórz uporządkowane wizualne reprezentacje treści, w tym mapy pojęć, schematy blokowe, diagramy Venna oraz organizatory przyczyn i skutków.",
      "sidebar_visuals_title": "Wizualna wsparcie",
      "sidebar_visuals_desc": "Obrazy generowane przez AI i pomoce wizualne wspierające zrozumienie. Twórz niestandardowe wizualizacje lub ulepszone zestawy obrazów dla treści.",
      "sidebar_faq_title": "Generator FAQ",
      "sidebar_faq_desc": "Generuj często zadawane pytania, które uczniowie mogą mieć na temat treści. Świetne do antycypowania zamieszania i przygotowywania wyjaśnień.",
      "sidebar_scaffolds_title": "Edukacyjne wsparcie",
      "sidebar_scaffolds_desc": "Uzyskaj strategie nauczania, wskazówki do dyskusji i wsparte aktywności dostosowane do twojej treści. Zawiera organizatory graficzne i prowadzoną praktykę.",
      "sidebar_quiz_title": "Exit Tickets i quizy",
      "sidebar_quiz_desc": "Twórz szybkie oceny kształtujące w celu sprawdzenia zrozumienia. Twórz pytania wielokrotnego wyboru, krótkie odpowiedzi lub interaktywne formaty quizów.",
      "sidebar_brainstorm_title": "Pomysły zaangażowania",
      "sidebar_brainstorm_desc": "Uzyskaj kreatywne haczyki, aktywności otwierające i strategie zaangażowania, aby wprowadzić twoją treść i utrzymać zainteresowanie uczniów.",
      "sidebar_games_title": "Interaktywne gry",
      "sidebar_games_desc": "Twórz gry edukacyjne, w tym talie fiszek, krzyżówki, karty Bingo i gry pamięciowe, używając słownictwa ze swojej treści.",
      "sidebar_resources_title": "Pakiet zasobów",
      "sidebar_resources_desc": "Pobieraj kompleksowe pakiety zasobów zawierające wszystkie wygenerowane materiały w formacie PDF do druku, do użytku w klasie.",
      "sidebar_adventure_title": "Edukacyjne przygody",
      "sidebar_adventure_desc": "Twórz interaktywne opowieści \"wybierz własną przygodę\" oparte na twojej treści. Uczniowie podejmują decyzje i eksplorują pojęcia poprzez narracyjną grę.",
      "sidebar_interview_title": "Wywiady historyczne",
      "sidebar_interview_desc": "Twórz Persony AI postaci historycznych lub bohaterów tekstu do symulowanych wywiadów i debat. Ożywiaj źródła pierwotne.",
      "default_title": "Temat pomocy",
      "default_desc": "Informacje o tej funkcji pojawią się tutaj. Kliknij dowolny element z ikoną pomocy, aby dowiedzieć się więcej."
    },
