    "wizard_level_select_title": "Poziom czytania",
    "wizard_dok_select": "Ustaw poziom Webb's Depth of Knowledge. Poziom 1 (przypominanie) używa prostej treści opartej na faktach. Poziom 4 (rozszerzone myślenie) tworzy złożone teksty wymagające syntezy i analizy.",
    "wizard_dok_select_title": "Głębokość wiedzy",
