      "nuclear_export_eukaryotes": "Eksport jądrowy (eukarionty)",
      "mature_mrna_exits_through_nuclear_pore": "Dojrzałe mRNA wychodzi przez pory jądrowe do cytoplazmy.",
      "initiation_3": "Inicjacja",
      "small_ribosomal_subunit_binds_mrna_ini": "Mała podjednostka rybosomu wiąże się z mRNA. Inicjatorowe tRNA (z Met) wiąże się z kodonem startowym AUG. Dołącza duża podjednostka.",
      "elongation_2": "Elongacja",
      "each_cycle_aminoacyl_trna_enters_a_sit": "Każdy cykl: aminoacylo-tRNA wchodzi do miejsca A → tworzy się wiązanie peptydowe (katalizowane przez 23S rRNA, rybozym) → rybosom przesuwa się o jeden kodon → tRNA idzie A→P→E.",
      "termination_2": "Terminacja",
      "stop_codon_uaa_uag_uga_recognized_by_r": "Kodon stop (UAA/UAG/UGA) rozpoznawany przez czynniki uwalniające. Peptyd zostaje uwolniony, rybosom rozdziela się.",
      "folding_modification": "Fałdowanie + modyfikacja",
      "chaperones_hsp70_groel_help_proteins_f": "Chaperony (Hsp70, GroEL) pomagają białkom prawidłowo się fałdować. Modyfikacje potranslacyjne: fosforylacja, glikozylacja, cięcie, wiązania dwusiarczkowe.",
      "codon_changes_but_amino_acid_is_the_sa": "Kodon się zmienia, ale aminokwas pozostaje ten sam (nadmiarowość kodu genetycznego). Brak skutku.",
      "codon_changes_different_amino_acid_eff": "Kodon się zmienia → inny aminokwas. Skutek waha się od żadnego (substytucja konserwatywna) do poważnego (anemia sierpowata: Glu→Wal).",
      "codon_changes_stop_codon_truncated_pro": "Kodon się zmienia → kodon STOP. Skrócone białko, zwykle niefunkcjonalne.",
      "adds_nucleotide_s_if_not_a_multiple_of": "Dodaje nukleotyd(y). Jeśli nie jest to wielokrotność 3, przesuwa ramkę odczytu → wszystkie kodony poniżej się zmieniają. Zwykle poważne.",
      "removes_nucleotide_s_same_frameshift_c": "Usuwa nukleotyd(y). Ten sam skutek przesunięcia ramki co insercja.",
      "extra_copies_of_a_gene_or_region_can_l": "Dodatkowe kopie genu lub regionu. Może prowadzić do efektów dawki (zespół Downa = dodatkowy chromosom 21).",
      "segment_of_chromosome_flipped_may_disr": "Odcinek chromosomu odwrócony. Może zaburzyć geny w punktach pęknięcia.",
      "segment_moves_to_a_different_chromosom": "Odcinek przenosi się na inny chromosom. Słynny: chromosom Filadelfia (PBSz; fuzja BCR-ABL).",
      "repeating_unit_e_g_cag_expands_across_": "Jednostka powtarzalna (np. CAG) rozszerza się przez pokolenia. Huntington (powtórzenia CAG w HTT), zespół łamliwego X (CGG w FMR1), dystrofia miotoniczna.",
      "human_autosomes": "Ludzkie autosomy",
      "pairs_1_22_numbered_roughly_by_size_wi": "Pary 1-22 (numerowane z grubsza według wielkości, z wyjątkami: chr. 21 jest mniejszy niż chr. 22).",
      "sex_chromosomes": "Chromosomy płciowe",
      "xx_female_or_xy_male_y_is_much_smaller": "XX (kobieta) lub XY (mężczyzna). Y jest znacznie mniejszy, niesie niewiele genów (~70) w porównaniu z X (~800).",
      "total_human_chromosomes": "Suma ludzkich chromosomów",
      "23_pairs_diploid_in_somatic_cells_game": "23 pary (diploidalne w komórkach somatycznych). Gamety są haploidalne (23 chromosomy, brak par).",
      "total_human_genes": "Suma ludzkich genów",
      "surprisingly_few_many_genes_produce_mu": "Zaskakująco niewiele — wiele genów wytwarza liczne białka przez alternatywny splicing. Duża część genomu jest regulatorowa lub niekodująca.",
      "total_base_pairs_haploid": "Suma par zasad (haploidalna)",
      "if_stretched_out_1_8_m_of_dna_per_cell": "Rozciągnięte, ~1,8 m DNA na komórkę. Upakowane w jądrze ~10 µm dzięki histonom + superskrętom.",
      "mitochondrial_dna": "DNA mitochondrialne",
      "maternally_inherited_codes_for_37_gene": "Dziedziczone po matce. Koduje 37 genów (13 białek, 22 tRNA, 2 rRNA). Wiele kopii na mitochondrium.",
      "pcr_polymerase_chain_reaction": "PCR (Reakcja łańcuchowa polimerazy)",
      "amplifies_a_specific_dna_segment_by_2_": "Powiela określony odcinek DNA o 2ⁿ (n cykli). Wykorzystuje termostabilną polimerazę Taq. Podstawa nowoczesnej biologii molekularnej.",
      "sanger_sequencing": "Sekwencjonowanie Sangera",
      "reads_dna_sequence_using_chain_termina": "Odczytuje sekwencję DNA za pomocą kończących łańcuch dideoksynukleotydów. Długość odczytu ~800-1000 pz. Obecnie w dużej mierze zastąpione sekwencjonowaniem nowej generacji.",
      "next_gen_sequencing_ngs": "Sekwencjonowanie nowej generacji (NGS)",
      "massively_parallel_sequences_millions_": "Masowo równoległe — sekwencjonuje miliony fragmentów jednocześnie. Illumina dominuje. Długość odczytu ~100-300 pz, miliardy na przebieg.",
      "programmable_gene_editing_guide_rna_ta": "Programowalna edycja genów. RNA prowadzące kieruje nukleazę Cas9 na określone DNA. Cięcia umożliwiają nokaut genu lub insercję za pośrednictwem HDR. Nagroda Nobla 2020.",
      "crispr_base_editing": "Edycja zasad CRISPR",
      "edits_a_single_base_without_double_str": "Edytuje pojedynczą zasadę bez pęknięcia dwuniciowego. Mniej efektów poza celem niż Cas9.",
      "restriction_enzymes": "Enzymy restrykcyjne",
      "bacterial_proteins_that_cut_dna_at_spe": "Białka bakteryjne, które tną DNA w określonych sekwencjach 4-8 pz. Umożliwiły technologię rekombinowanego DNA. Nagroda Nobla 1978.",
      "dna_ligase": "Ligaza DNA",
      "joins_dna_fragments_via_phosphodiester": "Łączy fragmenty DNA za pomocą wiązań fosfodiestrowych. Ligaza DNA T4 to koń roboczy klonowania.",
      "gel_electrophoresis": "Elektroforeza żelowa",
      "separates_dna_fragments_by_size_in_an_": "Rozdziela fragmenty DNA według wielkości w polu elektrycznym. Mniejsze fragmenty migrują szybciej przez matrycę żelu.",
      "microarrays": "Mikromacierze",
      "thousands_of_dna_probes_on_a_chip_meas": "Tysiące sond DNA na chipie. Mierzą ekspresję genów lub wykrywają SNP równolegle.",
      "single_cell_rna_seq": "RNA-seq pojedynczych komórek",
      "sequences_mrna_from_individual_cells_r": "Sekwencjonuje mRNA z pojedynczych komórek. Ujawnia heterogeniczność typów komórek, którą pomija masowe RNA-seq.",
      "cryo_em_for_nucleic_acids": "Krio-EM dla kwasów nukleinowych",
      "near_atomic_structures_of_rna_dna_comp": "Struktury kompleksów RNA/DNA o niemal atomowej rozdzielczości bez krystalizacji. Szczególnie skuteczne dla rybosomów, spliceosomów, replisomów.",
      "long_read_sequencing_pacbio_nanopore": "Sekwencjonowanie długich odczytów (PacBio, Nanopore)",
      "read_lengths_up_to_100kb_vs_illumina_s": "Długość odczytu do 100 kb+ (wobec ~300 pz Illuminy). Lepsze dla wariantów strukturalnych, powtórzeń, transkryptów pełnej długości.",
      "differential_reproduction_based_on_her": "Różnicowa reprodukcja oparta na dziedzicznej zmienności. Geny poprawiające przeżycie/reprodukcję stają się częstsze w kolejnych pokoleniach.",
      "random_source_of_new_genetic_variation": "Losowe źródło nowej zmienności genetycznej. Większość jest neutralna lub szkodliwa; rzadko korzystna. Substrat selekcji.",
      "random_changes_in_allele_frequency_esp": "Losowe zmiany częstości alleli, zwłaszcza w małych populacjach. Efekt założyciela + wąskie gardła to skrajne przypadki.",
      "movement_of_alleles_between_population": "Przepływ alleli między populacjami przez migrację. Zmniejsza różnice między populacjami; zwiększa zróżnicowanie w obrębie populacji.",
      "formation_of_new_species_usually_via_r": "Powstawanie nowych gatunków, zwykle przez izolację rozrodczą. Allopatryczna (separacja geograficzna) najczęstsza.",
      "unrelated_organisms_evolve_similar_tra": "Niespokrewnione organizmy niezależnie rozwijają podobne cechy (skrzydła u ptaków + nietoperzy + owadów; oczy u kręgowców + głowonogów).",
      "all_life_shares_a_common_ancestor_luca": "Całe życie ma wspólnego przodka (LUCA). Dowody: wspólny kod genetyczny, rybosomy, ATP, glikoliza, podstawowa biochemia.",
